
// AC3 Dashboard Bootstrap (auto-generated by postinstall.cjs)
// Tries code-split server first (lower memory), falls back to legacy single bundle.
import { execSync } from "child_process";
import { existsSync, mkdirSync, readdirSync, writeFileSync, statSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";
import { freemem, totalmem } from "os";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const ROOT = resolve(__dirname, "..");
const DIST = __dirname;
const SERVER_SPLIT = resolve(DIST, "server", "index.js");
const SERVER_LEGACY = resolve(DIST, "_server.js");
const PUBLIC = resolve(DIST, "public");
const ASSETS = resolve(ROOT, ".client-assets");

function log(m) { console.log("[" + new Date().toISOString().slice(11,19) + "] [boot] " + m); }

log("AC3 starting...");
log("CWD=" + process.cwd() + " ROOT=" + ROOT);
log("Memory: " + Math.round(freemem()/1024/1024) + "MB free / " + Math.round(totalmem()/1024/1024) + "MB total");

try { log("Root files: " + readdirSync(ROOT).slice(0,20).join(", ")); } catch(e) { log("Cannot list root: " + e.message); }
try { log("Dist files: " + readdirSync(DIST).join(", ")); } catch(e) { log("Cannot list dist: " + e.message); }

// Determine which server bundle to use
let serverEntry = null;
if (existsSync(SERVER_SPLIT)) {
  serverEntry = SERVER_SPLIT;
  log("Using code-split server (" + Math.round(statSync(SERVER_SPLIT).size/1024/1024) + "MB entry, lazy chunks)");
} else if (existsSync(SERVER_LEGACY)) {
  serverEntry = SERVER_LEGACY;
  log("Using legacy single-bundle server (" + Math.round(statSync(SERVER_LEGACY).size/1024/1024) + "MB)");
} else {
  log("No server bundle found. Building with esbuild (split mode)...");
  const t = Date.now();
  const serverDir = resolve(DIST, "server");
  try {
    mkdirSync(serverDir, { recursive: true });
    execSync(
      "npx esbuild server/_core/index.ts --bundle --splitting --platform=node --target=node20 --outdir=dist/server --format=esm --packages=external",
      { cwd: ROOT, stdio: "inherit", timeout: 180000 }
    );
    serverEntry = SERVER_SPLIT;
    log("Server built (split) in " + ((Date.now()-t)/1000).toFixed(1) + "s");
  } catch(e) {
    log("Split build failed: " + e.message + ". Trying single bundle...");
    try {
      execSync(
        "npx esbuild server/_core/index.ts --bundle --platform=node --target=node20 --outfile=dist/_server.js --format=esm --packages=external",
        { cwd: ROOT, stdio: "inherit", timeout: 120000 }
      );
      serverEntry = SERVER_LEGACY;
      log("Server built (legacy) in " + ((Date.now()-t)/1000).toFixed(1) + "s");
    } catch(e2) {
      log("FATAL: Cannot build server: " + e2.message);
      process.exit(1);
    }
  }
}

// Copy client assets if missing
if (!existsSync(resolve(PUBLIC, "index.html"))) {
  if (existsSync(ASSETS)) {
    log("Copying client assets...");
    try {
      execSync("cp -r " + JSON.stringify(ASSETS) + " " + JSON.stringify(PUBLIC), { cwd: ROOT, timeout: 60000 });
      log("Assets copied");
    } catch(e) {
      log("Copy failed, creating fallback: " + e.message);
      mkdirSync(PUBLIC, { recursive: true });
      writeFileSync(resolve(PUBLIC, "index.html"),
        '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>AC3</title></head><body style="background:#0a0a0f;color:#e2e8f0;font-family:system-ui;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0"><div style="text-align:center"><h1>AC3 Dashboard</h1><p style="color:#94a3b8">Server running.</p></div></body></html>'
      );
    }
  } else {
    log("No client assets. Creating fallback HTML...");
    mkdirSync(PUBLIC, { recursive: true });
    writeFileSync(resolve(PUBLIC, "index.html"),
      '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>AC3</title></head><body style="background:#0a0a0f;color:#e2e8f0;font-family:system-ui;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0"><div style="text-align:center"><h1>AC3 Dashboard</h1><p style="color:#94a3b8">Server running.</p></div></body></html>'
    );
  }
} else {
  log("Client assets present.");
}

// Start the server
log("Importing server...");
await import(serverEntry);
